import { Link } from 'react-router-dom';
import { FaExternalLinkAlt } from 'react-icons/fa';

function SchemeCard({ scheme }) {
  return (
    <div className="bg-white p-6 rounded-lg shadow-md hover:shadow-lg transition-shadow border-l-4 border-green-500">
      <div className="flex flex-col md:flex-row">
        <div className="flex-grow">
          <h3 className="text-xl font-semibold text-green-700 mb-2">
            <Link to={`/schemes/${scheme._id}`} className="hover:text-green-800">
              {scheme.name}
            </Link>
          </h3>
          
          <div className="mb-3">
            <span className="bg-green-100 text-green-800 text-xs font-medium px-2.5 py-0.5 rounded mr-2">
              {scheme.department}
            </span>
            <span className="bg-blue-100 text-blue-800 text-xs font-medium px-2.5 py-0.5 rounded">
              {scheme.status || 'Active'}
            </span>
          </div>
          
          <p className="text-gray-600 mb-4">
            {scheme.description.length > 200
              ? `${scheme.description.substring(0, 200)}...`
              : scheme.description}
          </p>
          
          <div className="flex flex-wrap gap-2">
            <Link
              to={`/schemes/${scheme._id}`}
              className="text-blue-600 hover:text-blue-800 font-medium"
            >
              View Details
            </Link>
            
            {scheme.applicationUrl && (
              <a
                href={scheme.applicationUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="text-green-600 hover:text-green-800 font-medium flex items-center"
              >
                Apply Online <FaExternalLinkAlt className="ml-1 text-sm" />
              </a>
            )}
          </div>
        </div>
        
        {scheme.imageUrl && (
          <div className="w-full md:w-64 md:ml-4 mt-4 md:mt-0 flex-shrink-0">
            <img
              src={scheme.imageUrl}
              alt={scheme.name}
              className="rounded-lg w-full h-full object-cover"
            />
          </div>
        )}
      </div>
    </div>
  );
}

export default SchemeCard;
